"use client";

import { useEffect, useState } from "react";
import { checkUserPackage } from "@/app/utils/api";
import { useUser } from "@/app/hooks/useUser";
import clsx from "clsx";

interface Props {
  className?: string;
}

interface PlanState {
  loading: boolean;
  hasAccess: boolean;
  name: string;
  uploadsRemaining: number | null;
}

const initialState: PlanState = {
  loading: true,
  hasAccess: false,
  name: "",
  uploadsRemaining: null,
};

export default function PlanStatusPill({ className }: Props) {
  const { user, loading: userLoading } = useUser({ required: false });
  const [state, setState] = useState<PlanState>(initialState);

  useEffect(() => {
    let cancelled = false;
    if (userLoading) return;
    if (!user) {
      setState((prev) => ({ ...prev, loading: false, hasAccess: false, name: "", uploadsRemaining: null }));
      return;
    }

    (async () => {
      setState((prev) => ({ ...prev, loading: true }));
      try {
        const res = await checkUserPackage();
        if (cancelled) return;
        setState({
          loading: false,
          hasAccess: !!res?.hasAccess,
          name: res?.package || "",
          uploadsRemaining:
            typeof res?.uploadsRemaining === "number" ? Math.max(0, res.uploadsRemaining) : null,
        });
      } catch (error) {
        if (cancelled) return;
        setState({ loading: false, hasAccess: false, name: "", uploadsRemaining: null });
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [user, userLoading]);

  if (userLoading) {
    return (
      <div
        className={clsx(
          "inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/5 px-4 py-1.5 text-sm text-white/70",
          className,
        )}
      >
        Checking plan…
      </div>
    );
  }

  if (!user) return null;

  if (state.loading) {
    return (
      <div
        className={clsx(
          "inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/5 px-4 py-1.5 text-sm text-white/70",
          className,
        )}
      >
        Checking plan…
      </div>
    );
  }

  const remaining = state.uploadsRemaining ?? 0;
  const hasCredits = remaining > 0;
  const tone = hasCredits ? "text-cyan-200" : state.hasAccess ? "text-amber-300" : "text-rose-300";
  const bg = hasCredits ? "bg-cyan-500/10 border-cyan-500/30" : "bg-rose-500/10 border-rose-500/30";

  if (!state.hasAccess) {
    return (
      <div
        className={clsx(
          "inline-flex items-center gap-2 rounded-full border px-4 py-1.5 text-sm font-medium text-rose-200",
          "bg-rose-500/10 border-rose-500/30",
          className,
        )}
      >
        No active plan · 0 uploads
      </div>
    );
  }

  if (!hasCredits) {
    return (
      <div
        className={clsx(
          "inline-flex items-center gap-2 rounded-full border px-4 py-1.5 text-sm font-medium",
          "bg-amber-500/10 border-amber-500/40 text-amber-200",
          className,
        )}
      >
        {state.name ? `${state.name.toUpperCase()} · No uploads left` : "No uploads left"}
      </div>
    );
  }

  return (
    <div
      className={clsx(
        "inline-flex items-center gap-3 rounded-full border px-4 py-1.5 text-sm font-medium",
        bg,
        tone,
        className,
      )}
    >
      {state.name ? `${state.name.toUpperCase()} plan` : "Active plan"}
      <span className="text-white/80">•</span>
      <span className="text-white">{remaining}</span>
      <span className="text-white/70">uploads left</span>
    </div>
  );
}
